const knex = require('knex');
const db = knex({
  client: 'pg',
  connection: process.env.DATABASE_URL,
});
module.exports = db;

const express = require('express');
const router = express.Router();
const db = require('../db');

router.get('/profile', async (req, res) => {
  const user = await db('users').where({ id: req.userId }).first();
  res.json(user);
});

module.exports = router;

const jwt = require('jsonwebtoken');

function authenticate(req, res, next) {
  const header = req.headers.authorization;
  if (!header || !header.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing token' });
  }
  const token = header.slice(7);
  try {
    const payload = jwt.verify(token, process.env.JWT_SECRET);
    req.userId = payload.sub;
    req.userRole = payload.role;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired' });
    }
    return res.status(403).json({ error: 'Invalid token' });
  }
}

module.exports = { authenticate };

const express = require('express');
const router = express.Router();
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const db = require('../db');

const ACCESS_TTL = '15m';
const REFRESH_TTL = '7d';

function signAccess(userId, role) {
  return jwt.sign({ sub: userId, role }, process.env.JWT_SECRET, { expiresIn: ACCESS_TTL });
}

function signRefresh(userId) {
  return jwt.sign({ sub: userId }, process.env.REFRESH_SECRET, { expiresIn: REFRESH_TTL });
}

// POST /auth/login
router.post('/login', async (req, res) => {
  const { email, password } = req.body;
  if (!email || !password) {
    return res.status(400).json({ error: 'Email and password required' });
  }
  const user = await db('users').where({ email }).first();
  if (!user || !(await bcrypt.compare(password, user.password_hash))) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }
  const accessToken = signAccess(user.id, user.role);
  const refreshToken = signRefresh(user.id);
  await db('refresh_tokens').insert({
    user_id: user.id,
    token: refreshToken,
    expires_at: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
  });
  res.json({ accessToken, refreshToken });
});

// POST /auth/refresh
router.post('/refresh', async (req, res) => {
  const { refreshToken } = req.body;
  if (!refreshToken) return res.status(400).json({ error: 'Refresh token required' });
  let payload;
  try {
    payload = jwt.verify(refreshToken, process.env.REFRESH_SECRET);
  } catch {
    return res.status(401).json({ error: 'Invalid refresh token' });
  }
  const stored = await db('refresh_tokens')
    .where({ token: refreshToken, user_id: payload.sub })
    .where('expires_at', '>', new Date())
    .first();
  if (!stored) return res.status(401).json({ error: 'Refresh token revoked' });
  const user = await db('users').where({ id: payload.sub }).first();
  res.json({ accessToken: signAccess(user.id, user.role) });
});

// POST /auth/logout
router.post('/logout', async (req, res) => {
  const { refreshToken } = req.body;
  if (refreshToken) await db('refresh_tokens').where({ token: refreshToken }).delete();
  res.status(204).send();
});

module.exports = router;

const express = require('express');
const app = express();
app.use(express.json());
const usersRouter = require('./routes/users');
app.use('/users', usersRouter);
app.listen(3000);
